parameters.new_string:
  it('should paginate with large page size', () => {
    const result = paginate(items, 1, 100);
    expect(result.items).toEqual(items);
    expect(result.totalPages).toBe(1);
  });

  it('should not have duplicate items between page 1 and page 2', () => {
    const result1 = paginate(items, 1, 3);
    const result2 = paginate(items, 2, 3);
    expect(result1.items).toEqual([1, 2, 3]);
    expect(result2.items).toEqual([4, 5, 6]);
    // Ensure no overlap
    const overlap = result1.items.filter(item => result2.items.includes(item));
    expect(overlap).toEqual([]);
  });

  it('should produce consecutive non-overlapping pages covering all items', () => {
    const page1 = paginate(items, 1, 3);
    const page2 = paginate(items, 2, 3);
    const page3 = paginate(items, 3, 3);
    const page4 = paginate(items, 4, 3);
    const allPaged = [...page1.items, ...page2.items, ...page3.items, ...page4.items];
    expect(allPaged).toEqual(items);
  });
});

